package Core_java;

public class String_concate {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
       String first_name="Arun";
       String  last_name="Kumar";
       System.out.println("The full name is " + first_name+last_name);
       String person="human";
       int num=21;
       double d=21.5;
       System.out.println("string concatenate: " + person+num);
       System.out.println("string concatenate: " + person+d);
	}

}
